impl DiskCache {
    pub fn new<P: AsRef<Path>>(cache_dir: P) -> Result<Self, CacheError> {
        let cache_dir = cache_dir.as_ref().to_path_buf();
        fs::create_dir_all(&cache_dir)?;

        let index_file = cache_dir.join("cache_index.bin");

        let store = if index_file.exists() {
            let data = fs::read(&index_file)?;
            bincode::deserialize(&data)?
        } else {
            CacheStore::new()
        };

        Ok(Self {
            cache_dir,
            store,
            index_file,
        })
    }

    pub fn save(&self, key: &str, preferences: &UserPreferences) -> Result<(), CacheError> {
        let file_path = self.entry_path(key);
        let encoded = bincode::serialize(preferences)?;
        fs::write(&file_path, &encoded)?;
        Ok(())
    }

    pub fn load(&self, key: &str) -> Result<UserPreferences, CacheError> {
        let file_path = self.entry_path(key);
        if !file_path.exists() {
            return Err(CacheError::EntryNotFound(key.to_string()));
        }
        let data = fs::read(&file_path)?;
        let preferences: UserPreferences = bincode::deserialize(&data)?;
        Ok(preferences)
    }

    pub fn put(&mut self, key: &str, preferences: UserPreferences) -> Result<(), CacheError> {
        self.save(key, &preferences)?;
        self.store.entries.insert(key.to_string(), preferences);
        self.flush_index()?;
        Ok(())
    }

    pub fn get(&self, key: &str) -> Result<&UserPreferences, CacheError> {
        self.store
            .entries
            .get(key)
            .ok_or_else(|| CacheError::EntryNotFound(key.to_string()))
    }

    pub fn get_or_load(&mut self, key: &str) -> Result<&UserPreferences, CacheError> {
        if !self.store.entries.contains_key(key) {
            let prefs = self.load(key)?;
            self.store.entries.insert(key.to_string(), prefs);
        }
        Ok(self.store.entries.get(key).unwrap())
    }

    pub fn remove(&mut self, key: &str) -> Result<(), CacheError> {
        self.store.entries.remove(key);
        let file_path = self.entry_path(key);
        if file_path.exists() {
            fs::remove_file(&file_path)?;
        }
        self.flush_index()?;
        Ok(())
    }

    pub fn keys(&self) -> Vec<&String> {
        self.store.entries.keys().collect()
    }

    pub fn contains(&self, key: &str) -> bool {
        self.store.entries.contains_key(key) || self.entry_path(key).exists()
    }

    pub fn clear(&mut self) -> Result<(), CacheError> {
        for key in self.store.entries.keys().cloned().collect::<Vec<_>>() {
            let file_path = self.entry_path(&key);
            if file_path.exists() {
                fs::remove_file(&file_path)?;
            }
        }
        self.store.entries.clear();
        self.flush_index()?;
        Ok(())
    }

    pub fn flush_index(&self) -> Result<(), CacheError> {
        let encoded = bincode::serialize(&self.store)?;
        fs::write(&self.index_file, &encoded)?;
        Ok(())
    }

    fn entry_path(&self, key: &str) -> PathBuf {
        let safe_key: String = key
            .chars()
            .map(|c| if c.is_alphanumeric() || c == '_' || c == '-' { c } else { '_' })
            .collect();
        self.cache_dir.join(format!("{}.bin", safe_key))
    }
}

