    fn test_cache_dir(name: &str) -> PathBuf {
        env::temp_dir().join(format!("rust_cache_test_{}", name))
    }

    fn cleanup(dir: &Path) {
        let _ = fs::remove_dir_all(dir);
    }

    #[test]
    fn test_save_and_load() {
        let dir = test_cache_dir("save_load");
        cleanup(&dir);

        let mut cache = DiskCache::new(&dir).unwrap();
        let prefs = UserPreferences::default();
        cache.put("test_user", prefs.clone()).unwrap();

        let loaded = cache.get("test_user").unwrap();
        assert_eq!(*loaded, prefs);

        cleanup(&dir);
    }

    #[test]
    fn test_persistence_across_instances() {
        let dir = test_cache_dir("persistence");
        cleanup(&dir);

        let prefs = UserPreferences {
            username: "persistent_user".to_string(),
            ..Default::default()
        };

        {
            let mut cache = DiskCache::new(&dir).unwrap();
            cache.put("user", prefs.clone()).unwrap();
        }

        {
            let mut cache = DiskCache::new(&dir).unwrap();
            let loaded = cache.get_or_load("user").unwrap();
            assert_eq!(*loaded, prefs);
        }

        cleanup(&dir);
    }

    #[test]
    fn test_remove_entry() {
        let dir = test_cache_dir("remove");
        cleanup(&dir);

        let mut cache = DiskCache::new(&dir).unwrap();
        cache.put("to_remove", UserPreferences::default()).unwrap();
        assert!(cache.contains("to_remove"));

        cache.remove("to_remove").unwrap();
        assert!(!cache.contains("to_remove"));

        cleanup(&dir);
    }

